        canonicalText("6f1ed002ab5595859014ebf0951522d9b0214b864e3ae49b43c9d9f9b8a47f76").shouldReturn("x509-profile-v1-sha256-6f1ed002ab5595859014ebf0951522d9b0214b864e3ae49b43c9d9f9b8a47f76");
    }

